import pika
import time
import threading
import json

# --- Publisher ---
def publisher():
    connection = None
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        channel = connection.channel()

        queue_name = 'task_queue'
        channel.queue_declare(queue=queue_name, durable=True)

        print("Publisher started. Sending messages...")

        for i in range(1, 11):
            task = {'task_id': i, 'description': f'Process data for item {i}', 'duration_seconds': i}
            message = json.dumps(task)
            channel.basic_publish(
                exchange='',
                routing_key=queue_name,
                body=message,
                properties=pika.BasicProperties(
                    delivery_mode=pika.spec.PERSISTENT_DELIVERY_MODE
                )
            )
            print(f" [x] Sent '{message}'")
            time.sleep(1) # Simulate some work between sending messages

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Error connecting to RabbitMQ: {e}")
        print("Please ensure RabbitMQ server is running on localhost:5672")
    except Exception as e:
        print(f"An unexpected error occurred in publisher: {e}")
    finally:
        if connection and not connection.is_closed:
            connection.close()
            print("Publisher connection closed.")

# --- Consumer ---
def consumer():
    connection = None
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        channel = connection.channel()

        queue_name = 'task_queue'
        channel.queue_declare(queue=queue_name, durable=True)

        print('Consumer started. Waiting for messages. To exit press CTRL+C')

        def callback(ch, method, properties, body):
            task = json.loads(body)
            print(f" [x] Received {task}")
            try:
                # Simulate processing time
                duration = task.get('duration_seconds', 1)
                print(f"     Processing task {task['task_id']} for {duration} seconds...")
                time.sleep(duration)
                print(f" [x] Done processing task {task['task_id']}")
            except Exception as e:
                print(f" [!] Error processing task {task['task_id']}: {e}")
            finally:
                ch.basic_ack(delivery_tag=method.delivery_tag)

        channel.basic_qos(prefetch_count=1)
        channel.basic_consume(queue=queue_name, on_message_callback=callback)

        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Error connecting to RabbitMQ: {e}")
        print("Please ensure RabbitMQ server is running on localhost:5672")
    except KeyboardInterrupt:
        print("Consumer stopped by user.")
    except Exception as e:
        print(f"An unexpected error occurred in consumer: {e}")
    finally:
        if connection and not connection.is_closed:
            connection.close()
            print("Consumer connection closed.")

# --- Main Application ---
if __name__ == "__main__":
    # Start consumer in a separate thread
    consumer_thread = threading.Thread(target=consumer)
    consumer_thread.start()

    # Give the consumer a moment to start up
    time.sleep(2)

    # Start publisher in the main thread
    publisher()

    # Wait for the consumer thread to finish (though it usually runs indefinitely until KeyboardInterrupt)
    # For this example, we'll just let the publisher finish and then the main program will exit,
    # leaving the consumer thread running in the background until manually stopped.
    # In a real-world scenario, you might manage these threads more robustly.
    print("\nPublisher finished sending messages. Consumer continues to run. Press CTRL+C to stop consumer.")
    # To keep the main thread alive and allow consumer to run indefinitely
    # while waiting for user interruption:
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        print("Main application received KeyboardInterrupt. Exiting.")